import{_ as l,o as n,c as s,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 12 章 文件、版本、终稿与归档治理","description":"文件整理不是“把桌面变干净”，而是保证材料找得到、版本分得清、原件不被误改、成果能够交接。 在不破坏原始文件的前提下，建立清楚的目录、版本关系、文件清单和处理日志。 一个虚构专题目录中有 32 个文件，其中同名文件 4 个、状态不明文件 3 个。WorkBuddy 应先生成清单和建议目录…","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md","lastUpdated":1784100816000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 12 章 从整理桌面文件这些小事做起/index.md"};function t(o,a,r,p,d,h){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-12-章-文件、版本、终稿与归档治理" tabindex="-1">第 12 章 文件、版本、终稿与归档治理 <a class="header-anchor" href="#第-12-章-文件、版本、终稿与归档治理" aria-label="Permalink to &quot;第 12 章 文件、版本、终稿与归档治理&quot;">​</a></h1><p>文件整理不是“把桌面变干净”，而是保证材料找得到、版本分得清、原件不被误改、成果能够交接。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>整理一个项目或专题工作目录。</li><li>区分草稿、审核稿、定稿、签署版和归档版。</li><li>批量检查重复文件、异常命名和缺失材料。</li><li>迁移或交接文件前形成可核对清单。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>在不破坏原始文件的前提下，建立清楚的目录、版本关系、文件清单和处理日志。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>明确的工作目录和只读原始目录。</li><li>文件分类、命名和归档要求。</li><li>允许移动、复制或重命名的范围。</li><li>交接对象、截止时间和验收清单。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><ol><li><strong>只读预检</strong>：统计文件类型、数量、大小、日期和异常，先不移动。</li><li><strong>识别版本</strong>：根据文件名、修改时间和内容摘要建立版本关系，状态不明的进入待确认区。</li><li><strong>设计目录</strong>：按任务而不是按软件分类，例如“01_任务说明、02_输入材料、03_过程稿、04_审核稿、05_正式成果、99_待确认”。</li><li><strong>生成变更预览</strong>：列出原路径、拟操作、新路径和冲突处理，人工确认后再执行。</li><li><strong>保留日志</strong>：记录成功、跳过、冲突和失败；迁移后抽样打开文件并核对数量。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>一个虚构专题目录中有 32 个文件，其中同名文件 4 个、状态不明文件 3 个。WorkBuddy 应先生成清单和建议目录，不能根据“final”“最终”等文件名直接删除其他版本。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只读检查当前工作目录，暂时不要移动、删除、覆盖或重命名任何文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>目标：{整理/交接/归档/迁移}</span></span>
<span class="line"><span>分类规则：{规则或“请先建议”}</span></span>
<span class="line"><span>正式成果判断依据：{审批、签署、盖章、确认记录等}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>先输出：</span></span>
<span class="line"><span>1. 文件清单和异常；</span></span>
<span class="line"><span>2. 可能的重复与版本关系；</span></span>
<span class="line"><span>3. 建议目录；</span></span>
<span class="line"><span>4. 拟操作预览和冲突处理；</span></span>
<span class="line"><span>5. 无法判断、需要人工确认的文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>没有我确认，不执行写入操作。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>原始目录是否保持只读。</li><li>正式版本是否有可靠依据，而非只看文件名。</li><li>同名冲突、重复文件和敏感材料如何处理。</li><li>写入、移动、删除和归档是否有明确权限。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>文件清单完整，异常有标记。</li><li>每项写操作都有预览和确认记录。</li><li>原件没有被覆盖，失败可以回退。</li><li>归档后数量、路径和抽样内容核对一致。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>只按修改时间认定终稿，会忽略审批与签署依据。</li><li>一上来批量重命名，容易破坏外部引用。</li><li>只看命令没有输出，不代表任务失败或成功，应检查日志和文件状态。</li><li>删除、覆盖和外部归档必须人工确认；可复用资产包括文件清单、目录模板、变更预览和处理日志。</li></ul>`,20)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
